
#!/usr/bin/env python
from __future__ import annotations
import argparse, json, re, shutil, uuid
from datetime import datetime
from pathlib import Path
from typing import List, Dict, Any

PATCH_MARKER_PREFIX = "AUTO-PATCH HANDCRAFTED CORI/MMACE COMPARATOR v2"

COMMON_HELPERS = '\n# ============================================================\n# AUTO-PATCH HANDCRAFTED CORI/MMACE COMPARATOR v2\n# Common helpers for handcrafted retinal feature analysis\n# ============================================================\n\nimport re, json, pickle, math, warnings\nfrom pathlib import Path\nimport numpy as np\nimport pandas as pd\nimport matplotlib.pyplot as plt\n\nwarnings.filterwarnings("ignore")\n\nHANDCRAFTED_DIR = Path(r"__HANDCRAFTED_DIR__")\nHANDCRAFTED_ID_REGEX = r"(\\d+)"\n\ndef _hc_clean_id(x):\n    return pd.Series(x).astype(str).str.replace(r"\\.0$", "", regex=True).str.strip()\n\ndef _hc_safe_name(s):\n    return re.sub(r"[^A-Za-z0-9]+", "_", str(s)).strip("_")\n\ndef _hc_log(msg):\n    try:\n        logger.log(msg)\n    except Exception:\n        print(msg)\n\ndef load_handcrafted_feature_folder(feature_dir=HANDCRAFTED_DIR, id_regex=HANDCRAFTED_ID_REGEX, recursive=False, save_inventory_path=None):\n    """\n    Load one handcrafted-feature CSV per subject/image and aggregate to one row per eid.\n    """\n    feature_dir = Path(feature_dir)\n    if not feature_dir.exists():\n        raise FileNotFoundError(f"Handcrafted feature folder not found: {feature_dir}")\n    files = sorted(feature_dir.rglob("*.csv") if recursive else feature_dir.glob("*.csv"))\n    if len(files) == 0:\n        raise FileNotFoundError(f"No CSV files found in handcrafted feature folder: {feature_dir}")\n\n    rows, inventory = [], []\n    for fp in files:\n        m = re.search(id_regex, fp.stem)\n        if not m:\n            inventory.append({"file": str(fp), "status": "skip_no_id", "eid": None, "n_rows": np.nan, "n_cols": np.nan})\n            continue\n        eid = str(m.group(1))\n        try:\n            df = pd.read_csv(fp, low_memory=False)\n        except Exception as e:\n            inventory.append({"file": str(fp), "status": f"read_fail: {str(e)[:80]}", "eid": eid, "n_rows": np.nan, "n_cols": np.nan})\n            continue\n\n        out = {"eid": eid, "source_file": fp.name}\n        n_numeric = 0\n        for c in df.columns:\n            cl = str(c).strip()\n            if cl.lower() in {"eid", "id", "subject_id", "image", "image_id", "filename", "file", "path"}:\n                continue\n            x = pd.to_numeric(df[c], errors="coerce")\n            if x.notna().sum() > 0:\n                feat_name = f"hc_{cl}"\n                out[feat_name] = float(x.mean())\n                n_numeric += 1\n\n        if n_numeric == 0:\n            inventory.append({"file": str(fp), "status": "skip_no_numeric_features", "eid": eid, "n_rows": len(df), "n_cols": df.shape[1]})\n            continue\n        rows.append(out)\n        inventory.append({"file": str(fp), "status": "ok", "eid": eid, "n_rows": len(df), "n_cols": df.shape[1], "n_numeric_features": n_numeric})\n\n    inv = pd.DataFrame(inventory)\n    if save_inventory_path is not None:\n        Path(save_inventory_path).parent.mkdir(parents=True, exist_ok=True)\n        inv.to_csv(save_inventory_path, index=False)\n\n    if len(rows) == 0:\n        raise ValueError("No usable handcrafted feature rows were loaded.")\n\n    feat_df = pd.DataFrame(rows)\n    feat_df["eid"] = _hc_clean_id(feat_df["eid"])\n    numeric_cols = [c for c in feat_df.columns if c.startswith("hc_")]\n    feat_df = feat_df.groupby("eid", as_index=False)[numeric_cols].mean()\n\n    _hc_log(f"Loaded handcrafted features: subjects={len(feat_df)}, features={len(numeric_cols)}, folder={feature_dir}")\n    return feat_df\n\ndef merge_handcrafted_features(df, hc_df, logger_name="cohort"):\n    d = df.copy()\n    if "eid" not in d.columns:\n        raise ValueError("Input cohort must contain eid.")\n    d["eid"] = _hc_clean_id(d["eid"])\n    hc = hc_df.copy()\n    hc["eid"] = _hc_clean_id(hc["eid"])\n    before = len(d)\n    merged = d.merge(hc, on="eid", how="left")\n    hc_cols = [c for c in hc.columns if c.startswith("hc_")]\n    has_any = merged[hc_cols].notna().any(axis=1) if hc_cols else pd.Series(False, index=merged.index)\n    _hc_log(f"{logger_name}: N={before}; matched handcrafted N={int(has_any.sum())}; hc_features={len(hc_cols)}")\n    return merged, hc_cols\n\ndef filter_handcrafted_feature_cols(train_df, hc_cols, max_missing=0.50, min_variance=1e-10, table_path=None):\n    rows, keep = [], []\n    for c in hc_cols:\n        x = pd.to_numeric(train_df[c], errors="coerce") if c in train_df.columns else pd.Series(dtype=float)\n        miss = float(x.isna().mean()) if len(x) else 1.0\n        var = float(x.var(skipna=True)) if x.notna().sum() > 1 else np.nan\n        ok = (miss <= max_missing) and np.isfinite(var) and (var > min_variance)\n        rows.append({"feature": c, "missing_fraction": miss, "variance": var, "status": "keep" if ok else "drop"})\n        if ok:\n            keep.append(c)\n    out = pd.DataFrame(rows)\n    if table_path is not None:\n        Path(table_path).parent.mkdir(parents=True, exist_ok=True)\n        out.to_csv(table_path, index=False)\n    return keep, out\n\ndef hc_pretty_feature_name(feature):\n    s = str(feature).replace("hc_", "")\n    s = s.replace("_", " ")\n    s = re.sub(r"\\s+", " ", s).strip()\n    return s\n\ndef handcrafted_feature_family(feature):\n    s = str(feature).lower()\n    if "artery" in s or re.search(r"\\bart\\b", s):\n        return "Artery"\n    if "vein" in s or "venule" in s:\n        return "Vein"\n    if "vessel" in s or "vascular" in s:\n        return "Global vessel"\n    if "tortu" in s:\n        return "Tortuosity"\n    if "fractal" in s or "fd" in s:\n        return "Fractal/complexity"\n    if "density" in s or "area" in s or "coverage" in s:\n        return "Density/area"\n    if "width" in s or "diam" in s or "caliber" in s or "crae" in s or "crve" in s:\n        return "Caliber"\n    if "branch" in s or "bifur" in s:\n        return "Branching"\n    return "Other"\n\ndef feature_rank_transition_interpretable(rank_a, rank_b, model_a_label, model_b_label, figdir, tabledir, top_n=25, prefix="HC"):\n    """\n    Interpretable handcrafted feature-rank transition plot.\n    """\n    from matplotlib.lines import Line2D\n    figdir = Path(figdir); tabledir = Path(tabledir)\n    figdir.mkdir(parents=True, exist_ok=True); tabledir.mkdir(parents=True, exist_ok=True)\n\n    def prep(rank, label):\n        r = rank.copy()\n        if "status" in r.columns:\n            r = r[r["status"].astype(str).eq("ok")].copy()\n        for col in ["p", "z_abs", "importance", "hr_per_sd", "coef"]:\n            if col in r.columns:\n                r[col] = pd.to_numeric(r[col], errors="coerce")\n        if "importance" not in r.columns:\n            r["importance"] = np.nan\n        if "p" in r.columns:\n            r["importance"] = r["importance"].fillna(-np.log10(r["p"].clip(lower=1e-300)))\n        if "p" in r.columns and "z_abs" in r.columns:\n            r = r.sort_values(["p", "z_abs"], ascending=[True, False])\n        elif "importance" in r.columns:\n            r = r.sort_values("importance", ascending=False)\n        r = r.drop_duplicates("feature", keep="first").reset_index(drop=True)\n        r[f"{label}_rank"] = np.arange(1, len(r)+1)\n        r[f"{label}_importance"] = r["importance"]\n        r[f"{label}_hr"] = r["hr_per_sd"] if "hr_per_sd" in r.columns else np.nan\n        return r[["feature", f"{label}_rank", f"{label}_importance", f"{label}_hr"]]\n\n    a = prep(rank_a, "A")\n    b = prep(rank_b, "B")\n    m = a.merge(b, on="feature", how="outer")\n    sel = m[(m["A_rank"].le(top_n)) | (m["B_rank"].le(top_n))].copy()\n    if sel.empty:\n        print("No features available for handcrafted feature transition.")\n        return sel\n\n    cap = top_n + 1\n    sel["A_plot_rank"] = sel["A_rank"].where(sel["A_rank"].le(top_n), cap).fillna(cap)\n    sel["B_plot_rank"] = sel["B_rank"].where(sel["B_rank"].le(top_n), cap).fillna(cap)\n    sel["rank_shift_B_minus_A"] = sel["B_rank"] - sel["A_rank"]\n    sel["plot_rank_shift_B_minus_A"] = sel["B_plot_rank"] - sel["A_plot_rank"]\n    sel["pretty_feature"] = sel["feature"].map(hc_pretty_feature_name)\n    sel["family"] = sel["feature"].map(handcrafted_feature_family)\n    sel["best_rank"] = sel[["A_rank", "B_rank"]].min(axis=1)\n    sel = sel.sort_values(["best_rank", "A_rank", "B_rank"], na_position="last").head(max(2*top_n, top_n)).copy()\n\n    family_palette = {\n        "Artery": "tab:red",\n        "Vein": "tab:blue",\n        "Global vessel": "tab:green",\n        "Tortuosity": "tab:purple",\n        "Fractal/complexity": "tab:brown",\n        "Density/area": "tab:orange",\n        "Caliber": "tab:pink",\n        "Branching": "tab:olive",\n        "Other": "0.45",\n    }\n\n    sel.to_csv(tabledir / f"{prefix}_handcrafted_feature_transition_table.csv", index=False)\n\n    fig_h = max(7.5, min(14, 0.32*len(sel)+2.5))\n    fig, ax = plt.subplots(figsize=(11.5, fig_h))\n\n    def lab_rank(x):\n        if pd.isna(x) or x > top_n:\n            return f">{top_n}"\n        return str(int(x))\n\n    for _, r in sel.iterrows():\n        color = family_palette.get(r["family"], "0.45")\n        ax.plot([0,1], [r["A_plot_rank"], r["B_plot_rank"]], color=color, alpha=0.72, linewidth=1.7)\n        sA = 35 + 14*(r["A_importance"] if np.isfinite(r["A_importance"]) else 0)\n        sB = 35 + 14*(r["B_importance"] if np.isfinite(r["B_importance"]) else 0)\n        ax.scatter([0], [r["A_plot_rank"]], s=float(np.clip(sA, 35, 180)), color=color, edgecolor="white", linewidth=0.6, zorder=3)\n        ax.scatter([1], [r["B_plot_rank"]], s=float(np.clip(sB, 35, 180)), color=color, edgecolor="white", linewidth=0.6, zorder=3)\n        ax.text(-0.035, r["A_plot_rank"], f"{r[\'pretty_feature\']} ({lab_rank(r[\'A_rank\'])})", ha="right", va="center", fontsize=7.2)\n        ax.text(1.035, r["B_plot_rank"], f"{r[\'pretty_feature\']} ({lab_rank(r[\'B_rank\'])})", ha="left", va="center", fontsize=7.2)\n\n    ax.set_xlim(-0.72, 1.72)\n    ax.set_ylim(cap+0.8, 0.5)\n    ax.set_xticks([0,1])\n    ax.set_xticklabels([model_a_label, model_b_label])\n    yticks = list(range(1, top_n+1, 2)) + [cap]\n    ax.set_yticks(yticks)\n    ax.set_yticklabels([str(x) for x in yticks[:-1]] + [f">{top_n}"])\n    ax.set_ylabel("Handcrafted feature rank; 1 = strongest univariate Cox association")\n    ax.set_title(f"Interpretable handcrafted feature-rank transition: {model_a_label} vs {model_b_label}", fontweight="bold")\n    ax.grid(axis="y", alpha=0.18)\n    ax.spines[["top","right"]].set_visible(False)\n\n    handles = [Line2D([0],[0], color=v, lw=3, label=k) for k,v in family_palette.items() if k in set(sel["family"])]\n    ax.legend(handles=handles, loc="lower center", bbox_to_anchor=(0.5, -0.20), ncol=3, frameon=False, fontsize=8)\n    fig.tight_layout()\n    savefig(fig, figdir / f"{prefix}_handcrafted_feature_transition_interpretable")\n    plt.show()\n    return sel\n\ndef save_hc_model_summary(prefix, selected_features, manifest, tabledir):\n    out = pd.DataFrame({\n        "rank": np.arange(1, len(selected_features)+1),\n        "feature": selected_features,\n        "pretty_feature": [hc_pretty_feature_name(f) for f in selected_features],\n        "family": [handcrafted_feature_family(f) for f in selected_features],\n    })\n    out.to_csv(Path(tabledir) / f"{prefix}_selected_handcrafted_features_interpretable.csv", index=False)\n    Path(tabledir, f"{prefix}_handcrafted_model_manifest.json").write_text(json.dumps(manifest, indent=2, default=str), encoding="utf-8")\n    return out\n'
H1_CELL = '\n# ============================================================\n# AUTO-PATCH HANDCRAFTED CORI/MMACE COMPARATOR v2\n# H1: train cancer-trained handcrafted retinal comparator HCORI\n# ============================================================\n\nlogger.section("Handcrafted retinal-feature comparator: train HCORI in cancer development cohort")\n\nhc_df = load_handcrafted_feature_folder(\n    HANDCRAFTED_DIR,\n    save_inventory_path=TABLEDIR / "H1_handcrafted_file_inventory.csv",\n)\n\ncancer_train_hc, hc_cols_train = merge_handcrafted_features(cancer_train, hc_df, "Cancer development")\ncancer_test_hc, hc_cols_test = merge_handcrafted_features(cancer_test, hc_df, "Cancer held-out")\n\nhc_cols = sorted(list(set(hc_cols_train).intersection(set(hc_cols_test))))\nhc_keep, hc_filter = filter_handcrafted_feature_cols(\n    cancer_train_hc,\n    hc_cols,\n    max_missing=0.50,\n    min_variance=1e-10,\n    table_path=TABLEDIR / "H1_HCORI_handcrafted_feature_filter.csv",\n)\n\nlogger.log(f"HCORI handcrafted features available={len(hc_cols)}; retained after filter={len(hc_keep)}")\n\nif len(hc_keep) < 2:\n    raise ValueError("Too few usable handcrafted features for HCORI. Check HANDCRAFTED_DIR and feature CSV format.")\n\ncancer_train_hc, cancer_test_hc, hcori_features, hcori_rank, hcori_bundle, hcori_manifest, hcori_cv = train_locked_model(\n    cancer_train_hc,\n    cancer_test_hc,\n    hc_keep,\n    prefix="HCORI",\n    outdir=TABLEDIR,\n    modeldir=MODELDIR,\n    logger=logger,\n    variance_threshold=1e-10,\n    max_missing=0.50,\n    candidate_ks=[5, 10, 15, 20, 30, 50],\n    cox_rank_penalizer=0.01,\n)\n\nhcori_selected_table = save_hc_model_summary("H1_HCORI", hcori_features, hcori_manifest, TABLEDIR)\nlogger.df("HCORI selected handcrafted features", hcori_selected_table)\n\ncori_perf_row = performance_row(cancer_test, "Held-out RetFound CORI", "CORI_score", "CORI_high_risk")\nhcori_perf_row = performance_row(cancer_test_hc, "Held-out handcrafted HCORI", "HCORI_score", "HCORI_high_risk")\nretfound_vs_hc = pd.DataFrame([cori_perf_row, hcori_perf_row])\nretfound_vs_hc.to_csv(TABLEDIR / "H1_Table_handcrafted_vs_retfound_CORI_performance.csv", index=False)\nlogger.df("RetFound CORI vs handcrafted HCORI performance", retfound_vs_hc)\n\nplot_km_high_low(cancer_test_hc, "HCORI_score", "HCORI_high_risk", "Handcrafted HCORI high vs low risk — held-out cancer", FIGDIR / "H1_HCORI_KM_high_low_heldout")\nplot_km_tertiles(cancer_test_hc, "HCORI_score", "HCORI_risk_tertile", "Handcrafted HCORI tertiles — held-out cancer", FIGDIR / "H1_HCORI_KM_tertiles_heldout")\n\nhc_score_cols = [c for c in ["eid", "time", "event", "HCORI_score", "HCORI_high_risk", "HCORI_risk_tertile"] if c in cancer_test_hc.columns]\npd.concat([\n    cancer_train_hc[hc_score_cols].assign(set="development"),\n    cancer_test_hc[hc_score_cols].assign(set="held_out"),\n], ignore_index=True).to_csv(TABLEDIR / "H1_HCORI_risk_scores_all_sets.csv", index=False)\n\nlogger.log("Saved H1 handcrafted HCORI model and outputs.")\n'
H2_CELL = '\n# ============================================================\n# AUTO-PATCH HANDCRAFTED CORI/MMACE COMPARATOR v2\n# H2: train non-cancer handcrafted H-M-MACE and compare with H1 HCORI\n# ============================================================\n\nlogger.section("Handcrafted retinal-feature comparator: train non-cancer H-M-MACE and compare with HCORI")\n\nhc_df = load_handcrafted_feature_folder(\n    HANDCRAFTED_DIR,\n    save_inventory_path=TABLEDIR / "H2_handcrafted_file_inventory.csv",\n)\n\ncancer_train_hc, _ = merge_handcrafted_features(cancer_train, hc_df, "Cancer development")\ncancer_test_hc, _ = merge_handcrafted_features(cancer_test, hc_df, "Cancer held-out")\nnc_train_hc, _ = merge_handcrafted_features(nc_train, hc_df, "Non-cancer development")\nnc_test_hc, _ = merge_handcrafted_features(nc_test, hc_df, "Non-cancer held-out")\n\nhc_cols_all = [c for c in hc_df.columns if c.startswith("hc_")]\nhc_keep, hc_filter = filter_handcrafted_feature_cols(\n    nc_train_hc,\n    hc_cols_all,\n    max_missing=0.50,\n    min_variance=1e-10,\n    table_path=TABLEDIR / "H2_HMMACE_handcrafted_feature_filter.csv",\n)\nlogger.log(f"H-M-MACE handcrafted features available={len(hc_cols_all)}; retained after filter={len(hc_keep)}")\n\nif len(hc_keep) < 2:\n    raise ValueError("Too few usable handcrafted features for H-M-MACE.")\n\nHCORI_BUNDLE_PATH = H1_LOCKED_OUTDIR / "models" / "HCORI_locked_model_bundle.pkl"\nif not HCORI_BUNDLE_PATH.exists():\n    raise FileNotFoundError(f"Missing H1 HCORI model bundle: {HCORI_BUNDLE_PATH}. Run patched H1 first.")\n\nhcori_bundle = load_model_bundle(HCORI_BUNDLE_PATH)\ncancer_test_hc = apply_model_bundle(hcori_bundle, cancer_test_hc, score_col="HCORI_score", prefix="HCORI", logger=logger)\nnc_test_hc = apply_model_bundle(hcori_bundle, nc_test_hc, score_col="HCORI_score", prefix="HCORI", logger=logger)\n\nnc_train_hc, nc_test_hc, hmmace_features, hmmace_rank, hmmace_bundle, hmmace_manifest, hmmace_cv = train_locked_model(\n    nc_train_hc,\n    nc_test_hc,\n    hc_keep,\n    prefix="HMMACE",\n    outdir=TABLEDIR,\n    modeldir=MODELDIR,\n    logger=logger,\n    variance_threshold=1e-10,\n    max_missing=0.50,\n    candidate_ks=[5, 10, 15, 20, 30, 50],\n    cox_rank_penalizer=0.01,\n)\n\nhmmace_selected_table = save_hc_model_summary("H2_HMMACE", hmmace_features, hmmace_manifest, TABLEDIR)\nlogger.df("H-M-MACE selected handcrafted features", hmmace_selected_table)\n\ncancer_test_hc = apply_model_bundle(hmmace_bundle, cancer_test_hc, score_col="HMMACE_score", prefix="HMMACE", logger=logger)\n\nhc_perf_rows = []\nfor cohort_label, df_ in [("Cancer held-out", cancer_test_hc), ("Non-cancer held-out", nc_test_hc)]:\n    for model_label, score_col, group_col in [\n        ("Handcrafted cancer-trained HCORI", "HCORI_score", "HCORI_high_risk"),\n        ("Handcrafted non-cancer H-M-MACE", "HMMACE_score", "HMMACE_high_risk"),\n    ]:\n        if score_col in df_.columns and group_col in df_.columns:\n            row = performance_row(df_, cohort_label, score_col, group_col)\n            row["model"] = model_label\n            hc_perf_rows.append(row)\n\nhc_cross_perf = pd.DataFrame(hc_perf_rows)\nhc_cross_perf.to_csv(TABLEDIR / "H2_Table_handcrafted_HCORI_vs_HMMACE_cross_prediction.csv", index=False)\nlogger.df("Handcrafted HCORI vs H-M-MACE cross-prediction", hc_cross_perf)\n\nplot_km_high_low(cancer_test_hc, "HCORI_score", "HCORI_high_risk", "Handcrafted HCORI high vs low — cancer held-out", FIGDIR / "H2_HCORI_KM_cancer_heldout")\nplot_km_high_low(cancer_test_hc, "HMMACE_score", "HMMACE_high_risk", "Handcrafted H-M-MACE high vs low — cancer held-out", FIGDIR / "H2_HMMACE_KM_cancer_heldout")\nplot_km_high_low(nc_test_hc, "HMMACE_score", "HMMACE_high_risk", "Handcrafted H-M-MACE high vs low — non-cancer held-out", FIGDIR / "H2_HMMACE_KM_noncancer_heldout")\n\nfor cohort_label, df_ in [("Cancer held-out", cancer_test_hc), ("Non-cancer held-out", nc_test_hc)]:\n    rec = df_[["event", "HCORI_risk_tertile", "HMMACE_risk_tertile", "HCORI_score", "HMMACE_score"]].dropna().copy()\n    if len(rec) == 0:\n        logger.log(f"Skipping handcrafted reclassification for {cohort_label}: no complete rows.")\n        continue\n    cnt, er, mp = transition_heatmap(\n        rec, "HMMACE_risk_tertile", "HCORI_risk_tertile", "event", "HCORI_score",\n        f"Handcrafted H-M-MACE → HCORI strata ({cohort_label})",\n        FIGDIR / f"H2_handcrafted_reclassification_{_hc_safe_name(cohort_label)}",\n    )\n    cnt.to_csv(TABLEDIR / f"H2_handcrafted_reclassification_counts_{_hc_safe_name(cohort_label)}.csv")\n    er.to_csv(TABLEDIR / f"H2_handcrafted_reclassification_event_rates_{_hc_safe_name(cohort_label)}.csv")\n    mp.to_csv(TABLEDIR / f"H2_handcrafted_reclassification_mean_HCORI_score_{_hc_safe_name(cohort_label)}.csv")\n    alluvial_static(rec, "HMMACE_risk_tertile", "HCORI_risk_tertile", f"Handcrafted H-M-MACE → HCORI strata ({cohort_label})", FIGDIR / f"H2_handcrafted_alluvial_{_hc_safe_name(cohort_label)}")\n\nhcori_rank = hcori_bundle.get("feature_ranking")\nif not isinstance(hcori_rank, pd.DataFrame):\n    hcori_rank = pd.read_csv(H1_LOCKED_OUTDIR / "tables" / "HCORI_feature_univariate_cox_ranking.csv")\n\nhc_rank_shift = feature_rank_transition_interpretable(\n    hcori_rank, hmmace_rank,\n    model_a_label="Cancer-trained HCORI",\n    model_b_label="Non-cancer H-M-MACE",\n    figdir=FIGDIR,\n    tabledir=TABLEDIR,\n    top_n=25,\n    prefix="H2_HC",\n)\nlogger.df("Interpretable handcrafted feature-rank transition", hc_rank_shift)\n'
H3_CELL = '\n# ============================================================\n# AUTO-PATCH HANDCRAFTED CORI/MMACE COMPARATOR v2\n# H3: apply H1 HCORI across treatment strata\n# ============================================================\n\nlogger.section("Handcrafted HCORI treatment-stratified analysis")\n\nhc_df = load_handcrafted_feature_folder(HANDCRAFTED_DIR, save_inventory_path=TABLEDIR / "H3_handcrafted_file_inventory.csv")\ncancer_test_hc, _ = merge_handcrafted_features(cancer_test, hc_df, "Cancer held-out treatment cohort")\n\nHCORI_BUNDLE_PATH = H1_LOCKED_OUTDIR / "models" / "HCORI_locked_model_bundle.pkl"\nif not HCORI_BUNDLE_PATH.exists():\n    raise FileNotFoundError(f"Missing H1 HCORI model bundle: {HCORI_BUNDLE_PATH}. Run patched H1 first.")\nhcori_bundle = load_model_bundle(HCORI_BUNDLE_PATH)\ncancer_test_hc = apply_model_bundle(hcori_bundle, cancer_test_hc, score_col="HCORI_score", prefix="HCORI", logger=logger)\n\nhc_strata = []\nfor label, flag in [\n    ("All held-out cancer", None),\n    ("Treatment-naive", "treatment_naive"),\n    ("Any systemic treatment", "treatment_any"),\n    ("Chemotherapy", "chemo_any"),\n    ("Immunotherapy", "io_any"),\n]:\n    if flag is None:\n        sub = cancer_test_hc.copy()\n    elif flag in cancer_test_hc.columns:\n        sub = cancer_test_hc[pd.to_numeric(cancer_test_hc[flag], errors="coerce").fillna(0).eq(1)].copy()\n    else:\n        logger.log(f"Missing treatment flag for handcrafted HCORI: {flag}")\n        continue\n\n    row = performance_row(sub, label, "HCORI_score", "HCORI_high_risk") if len(sub) else {"cohort": label, "N": 0, "Events": 0}\n    hc_strata.append(row)\n\n    if len(sub) >= 30 and sub["event"].sum() >= 5 and sub["HCORI_high_risk"].nunique(dropna=True) >= 2:\n        plot_km_high_low(sub, "HCORI_score", "HCORI_high_risk", f"Handcrafted HCORI high vs low — {label}", FIGDIR / f"H3_HCORI_KM_{_hc_safe_name(label)}")\n\nhc_treat_perf = pd.DataFrame(hc_strata)\nhc_treat_perf.to_csv(TABLEDIR / "H3_Table_handcrafted_HCORI_treatment_performance.csv", index=False)\nlogger.df("Handcrafted HCORI treatment-stratified performance", hc_treat_perf)\n'
H4_CELL = '\n# ============================================================\n# AUTO-PATCH HANDCRAFTED CORI/MMACE COMPARATOR v2\n# H4: apply H1 HCORI to curated CMR phenotypes\n# ============================================================\n\nlogger.section("Handcrafted HCORI CMR phenotyping analysis")\n\nhc_df = load_handcrafted_feature_folder(HANDCRAFTED_DIR, save_inventory_path=TABLEDIR / "H4_handcrafted_file_inventory.csv")\n\nif "cmr_merged" in globals():\n    cmr_hc_base = cmr_merged.copy()\nelif "cmr_scored" in globals():\n    cmr_hc_base = cmr_scored.copy()\nelse:\n    cmr_hc_base = cancer_test.copy()\n\ncmr_hc, _ = merge_handcrafted_features(cmr_hc_base, hc_df, "CMR-linked held-out cohort")\n\nHCORI_BUNDLE_PATH = H1_LOCKED_OUTDIR / "models" / "HCORI_locked_model_bundle.pkl"\nif not HCORI_BUNDLE_PATH.exists():\n    raise FileNotFoundError(f"Missing H1 HCORI model bundle: {HCORI_BUNDLE_PATH}. Run patched H1 first.")\nhcori_bundle = load_model_bundle(HCORI_BUNDLE_PATH)\ncmr_hc = apply_model_bundle(hcori_bundle, cmr_hc, score_col="HCORI_score", prefix="HCORI", logger=logger)\n\nif "selected_cmr_cols" in globals():\n    hc_cmr_cols = selected_cmr_cols\nelif "cmr_cols" in globals():\n    hc_cmr_cols = cmr_cols\nelse:\n    hc_cmr_cols = cmr_feature_cols(cmr_hc, min_nonmissing=30)\n\nhc_cmr_table = cmr_analysis_table(cmr_hc, score_col="HCORI_score", group_col="HCORI_high_risk", cmr_cols=hc_cmr_cols, tabledir=TABLEDIR, prefix="H4_HCORI")\nlogger.df("Handcrafted HCORI CMR correlation/group-comparison table", hc_cmr_table)\n\nif len(hc_cmr_table):\n    top_hc_cmr = hc_cmr_table.sort_values(["Spearman_p", "Welch_p"], na_position="last")["feature"].head(6).tolist()\n    cmr_violin_grid(cmr_hc, top_hc_cmr, "HCORI_score", "HCORI_high_risk", FIGDIR, prefix="H4_HCORI")\n    cmr_cluster_map(cmr_hc, top_hc_cmr, FIGDIR, prefix="H4_HCORI_top")\n\ntry:\n    hc_covars, _ = one_age_covars(cmr_hc, logger=logger)\n    hc_adj = adjusted_linear_regressions(cmr_hc, score_col="HCORI_score", features=hc_cmr_cols[:50], covars=hc_covars, tabledir=TABLEDIR, prefix="H4_HCORI")\n    logger.df("Handcrafted HCORI adjusted CMR regressions", hc_adj)\nexcept Exception as e:\n    logger.log(f"Handcrafted HCORI adjusted CMR regressions skipped: {e}")\n'

def read_nb(path: Path) -> Dict[str, Any]:
    with path.open("r", encoding="utf-8") as f:
        return json.load(f)

def write_nb(path: Path, nb: Dict[str, Any]) -> None:
    with path.open("w", encoding="utf-8") as f:
        json.dump(nb, f, ensure_ascii=False, indent=1)

def cell_source(cell: Dict[str, Any]) -> str:
    src = cell.get("source", "")
    if isinstance(src, list):
        return "".join(src)
    return str(src)

def code_cell(source: str) -> Dict[str, Any]:
    return {"cell_type": "code", "execution_count": None, "id": str(uuid.uuid4())[:8], "metadata": {}, "outputs": [], "source": source}

def markdown_cell(source: str) -> Dict[str, Any]:
    return {"cell_type": "markdown", "id": str(uuid.uuid4())[:8], "metadata": {}, "source": source}

def remove_existing_patch_cells(nb: Dict[str, Any]) -> int:
    old = nb.get("cells", [])
    new = [c for c in old if PATCH_MARKER_PREFIX not in cell_source(c)]
    nb["cells"] = new
    return len(old) - len(new)

def find_insert_index(nb: Dict[str, Any], anchors: List[str]) -> int:
    idx = None
    for i, c in enumerate(nb.get("cells", [])):
        src = cell_source(c).lower()
        if any(a.lower() in src for a in anchors):
            idx = i + 1
    return idx if idx is not None else len(nb.get("cells", []))

def patch_one(path: Path, cells: List[Dict[str, Any]], anchors: List[str], dry_run: bool, force: bool, backup: bool) -> str:
    if not path.exists():
        return f"MISS: {path} does not exist"
    nb = read_nb(path)
    already = any(PATCH_MARKER_PREFIX in cell_source(c) for c in nb.get("cells", []))
    removed = 0
    if already:
        if not force:
            return f"SKIP: {path.name} already contains patch cells; use --force to replace"
        removed = remove_existing_patch_cells(nb)
    idx = find_insert_index(nb, anchors)
    for offset, cell in enumerate(cells):
        nb["cells"].insert(idx + offset, cell)
    if dry_run:
        return f"DRY: {path.name}: would insert {len(cells)} cells at index {idx}; removed_existing={removed}"
    if backup:
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        shutil.copy2(path, path.with_suffix(path.suffix + f".bak_{stamp}"))
    write_nb(path, nb)
    return f"OK: {path.name}: inserted {len(cells)} cells at index {idx}; removed_existing={removed}"

def build_cells(handcrafted_dir: str):
    common = COMMON_HELPERS.replace("__HANDCRAFTED_DIR__", handcrafted_dir.replace("\\", "\\\\"))
    return {
        "h1": [markdown_cell(f"## {PATCH_MARKER_PREFIX}: H1 handcrafted HCORI comparator"), code_cell(common), code_cell(H1_CELL)],
        "h2": [markdown_cell(f"## {PATCH_MARKER_PREFIX}: H2 handcrafted HCORI vs H-M-MACE"), code_cell(common), code_cell(H2_CELL)],
        "h3": [markdown_cell(f"## {PATCH_MARKER_PREFIX}: H3 handcrafted HCORI treatment analysis"), code_cell(common), code_cell(H3_CELL)],
        "h4": [markdown_cell(f"## {PATCH_MARKER_PREFIX}: H4 handcrafted HCORI CMR analysis"), code_cell(common), code_cell(H4_CELL)],
    }

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--h1", type=str, required=True)
    ap.add_argument("--h2", type=str, required=True)
    ap.add_argument("--h3", type=str, required=True)
    ap.add_argument("--h4", type=str, required=True)
    ap.add_argument("--handcrafted-dir", type=str, required=True)
    ap.add_argument("--dry-run", action="store_true")
    ap.add_argument("--force", action="store_true")
    ap.add_argument("--no-backup", action="store_true")
    args = ap.parse_args()

    cells = build_cells(args.handcrafted_dir)
    print("Handcrafted CORI/M-MACE patcher v2")
    print("="*80)
    print(f"Handcrafted folder: {args.handcrafted_dir}")
    print(f"Dry run: {args.dry_run}")
    print(f"Force: {args.force}")
    print()

    jobs = [
        ("H1", Path(args.h1), cells["h1"], ["output manifest", "primary pan-cancer", "Train pan-cancer", "CORI performance"]),
        ("H2", Path(args.h2), cells["h2"], ["feature-rank", "reclassification", "M-MACE", "cross-prediction"]),
        ("H3", Path(args.h3), cells["h3"], ["treatment", "treatment-stratified", "interaction"]),
        ("H4", Path(args.h4), cells["h4"], ["CMR", "curated", "cardiac magnetic"]),
    ]
    for name, path, cell_list, anchors in jobs:
        print(f"{name}: {patch_one(path, cell_list, anchors, args.dry_run, args.force, not args.no_backup)}")

    print("\nRun order after patching:")
    print("1) H1 first: trains/saves HCORI handcrafted cancer model.")
    print("2) H2 next: loads HCORI and trains H-M-MACE handcrafted non-cancer model.")
    print("3) H3 and H4 after H1: load HCORI for treatment/CMR secondary analyses.")
    print("\nKey output for your interpretable ribbon:")
    print("H2_HC_handcrafted_feature_transition_interpretable.png/pdf")
    print("H2_HC_handcrafted_feature_transition_table.csv")

if __name__ == "__main__":
    main()
